[Serializable]
public class Permission
{
    public string Name { get; set; }
    public string Resource { get; set; }
    public PermissionLevel Level { get; set; }

    public Permission(string name, string resource, PermissionLevel level)
    {
        Name = name;
        Resource = resource;
        Level = level;
    }

    public bool CanRead()
    {
        return Level >= PermissionLevel.Read;
    }

    public bool CanWrite()
    {
        return Level >= PermissionLevel.Write;
    }

    public bool CanDelete()
    {
        return Level >= PermissionLevel.Admin;
    }

    public bool HasAccessTo(string resourceName)
    {
        return string.Equals(Resource, resourceName, StringComparison.OrdinalIgnoreCase)
            || Resource == "*";
    }

    public override string ToString()
    {
        return $"Permission[{Name}] on {Resource} ({Level})";
    }
}

[Serializable]
public enum PermissionLevel
{
    None = 0,
    Read = 1,
    Write = 2,
    Admin = 3
}

[Serializable]
public class CartItem
{
    public string ProductId { get; set; }
    public string ProductName { get; set; }
    public decimal Price { get; set; }
