[Serializable]
public class ShoppingCart
{
    public List<CartItem> Items { get; set; } = new List<CartItem>();

    public void AddItem(string productId, string productName, decimal price, int quantity = 1)
    {
        var existing = Items.Find(i => i.ProductId == productId);
        if (existing != null)
        {
            existing.Quantity += quantity;
        }
        else
        {
            Items.Add(new CartItem(productId, productName, price, quantity));
        }
    }

    public bool RemoveItem(string productId)
    {
        return Items.RemoveAll(i => i.ProductId == productId) > 0;
    }

    public void UpdateQuantity(string productId, int quantity)
    {
        var item = Items.Find(i => i.ProductId == productId);
        if (item != null)
        {
            if (quantity <= 0)
                Items.Remove(item);
            else
                item.Quantity = quantity;
        }
    }

    public decimal GetCartTotal()
    {
        decimal total = 0;
        foreach (var item in Items)
        {
            total += item.GetTotal();
        }
        return total;
    }

    public int GetItemCount()
    {
        int count = 0;
        foreach (var item in Items)
        {
            count += item.Quantity;
        }
        return count;
    }

    public void Clear()
    {
        Items.Clear();
    }
}

