[Serializable]
public class UserSession
{
    public string SessionId { get; set; }
    public string UserId { get; set; }
    public string Username { get; set; }
    public string Email { get; set; }
    public DateTime CreatedAt { get; set; }
    public DateTime LastAccessedAt { get; set; }
    public DateTime? ExpiresAt { get; set; }
    public UserPreferences Preferences { get; set; }
    public ShoppingCart Cart { get; set; }
    public List<Permission> Permissions { get; set; }
    public Dictionary<string, object> AdditionalData { get; set; }

    public UserSession()
    {
        SessionId = Guid.NewGuid().ToString("N");
        CreatedAt = DateTime.UtcNow;
        LastAccessedAt = DateTime.UtcNow;
        Preferences = new UserPreferences();
        Cart = new ShoppingCart();
        Permissions = new List<Permission>();
        AdditionalData = new Dictionary<string, object>();
    }

    public UserSession(string userId, string username, string email, TimeSpan? sessionDuration = null)
        : this()
    {
        UserId = userId;
        Username = username;
        Email = email;
        if (sessionDuration.HasValue)
        {
            ExpiresAt = DateTime.UtcNow.Add(sessionDuration.Value);
        }
    }

    public bool IsExpired()
    {
        return ExpiresAt.HasValue && DateTime.UtcNow > ExpiresAt.Value;
    }

    public void Touch()
    {
        LastAccessedAt = DateTime.UtcNow;
    }

    public void AddPermission(string name, string resource, PermissionLevel level)
    {
        Permissions.Add(new Permission(name, resource, level));
    }

    public bool HasPermission(string resource, PermissionLevel requiredLevel)
    {
        foreach (var perm in Permissions)
        {
            if (perm.HasAccessTo(resource) && perm.Level >= requiredLevel)
                return true;
        }
        return false;
    }

    public List<Permission> GetPermissionsForResource(string resource)
    {
        return Permissions.FindAll(p => p.HasAccessTo(resource));
    }

    public void ExtendSession(TimeSpan duration)
    {
        ExpiresAt = DateTime.UtcNow.Add(duration);
    }

    public override string ToString()
    {
        return $"Session[{SessionId}] User={Username}({UserId}) Created={CreatedAt} " +
               $"Expires={ExpiresAt?.ToString() ?? "Never"} CartItems={Cart.GetItemCount()} " +
               $"Permissions={Permissions.Count}";
    }
}

public class SessionManager
{
    private readonly string _sessionDirectory;
    private readonly Dictionary<string, UserSession> _activeSessions;
    private readonly object _lock = new object();
    private readonly TimeSpan _defaultSessionDuration;

    public SessionManager(string sessionDirectory = null, TimeSpan? defaultSessionDuration = null)
    {
        _sessionDirectory = sessionDirectory ?? Path.Combine(Path.GetTempPath(), "sessions");
        _defaultSessionDuration = defaultSessionDuration ?? TimeSpan.FromHours(24);
        _activeSessions = new Dictionary<string, UserSession>();

        if (!Directory.Exists(_sessionDirectory))
        {
            Directory.CreateDirectory(_sessionDirectory);
        }
    }

    public UserSession CreateSession(string userId, string username, string email)
    {
        var session = new UserSession(userId, username, email, _defaultSessionDuration);

        lock (_lock)
        {
            _activeSessions[session.SessionId] = session;
        }

        SaveSession(session);
        Console.WriteLine($"[SessionManager] Created session: {session.SessionId} for user: {username}");
        return session;
    }

    public UserSession GetSession(string sessionId)
    {
        lock (_lock)
        {
            if (_activeSessions.TryGetValue(sessionId, out var cachedSession))
            {
                if (cachedSession.IsExpired())
                {
                    Console.WriteLine($"[SessionManager] Session expired: {sessionId}");
                    DestroySession(sessionId);
                    return null;
                }
                cachedSession.Touch();
                return cachedSession;
            }
        }

        var session = LoadSession(sessionId);
        if (session != null)
        {
            if (session.IsExpired())
            {
                Console.WriteLine($"[SessionManager] Loaded session is expired: {sessionId}");
                DestroySession(sessionId);
                return null;
            }

            session.Touch();
            lock (_lock)
            {
                _activeSessions[sessionId] = session;
            }
        }

        return session;
    }

    public void UpdateSession(UserSession session)
    {
        if (session == null) throw new ArgumentNullException(nameof(session));

        session.Touch();

        lock (_lock)
        {
            _activeSessions[session.SessionId] = session;
        }

        SaveSession(session);
        Console.WriteLine($"[SessionManager] Updated session: {session.SessionId}");
    }

    public void DestroySession(string sessionId)
    {
        lock (_lock)
        {
            _activeSessions.Remove(sessionId);
        }

        string filePath = GetSessionFilePath(sessionId);
        if (File.Exists(filePath))
        {
            File.Delete(filePath);
        }

        Console.WriteLine($"[SessionManager] Destroyed session: {sessionId}");
    }

    public List<UserSession> GetAllActiveSessions()
    {
        var sessions = new List<UserSession>();
        var files = Directory.GetFiles(_sessionDirectory, "*.session");

        foreach (var file in files)
        {
            var sessionId = Path.GetFileNameWithoutExtension(file);
            var session = LoadSession(sessionId);
            if (session != null && !session.IsExpired())
            {
                sessions.Add(session);
            }
        }

        return sessions;
    }

    public int CleanupExpiredSessions()
    {
        int cleaned = 0;
        var files = Directory.GetFiles(_sessionDirectory, "*.session");

        foreach (var file in files)
        {
            var sessionId = Path.GetFileNameWithoutExtension(file);
            var session = LoadSession(sessionId);
            if (session == null || session.IsExpired())
            {
                DestroySession(sessionId);
                cleaned++;
            }
        }

        Console.WriteLine($"[SessionManager] Cleaned up {cleaned} expired sessions.");
        return cleaned;
    }

    public UserSession GetSessionByUserId(string userId)
    {
        lock (_lock)
        {
            foreach (var kvp in _activeSessions)
            {
                if (kvp.Value.UserId == userId && !kvp.Value.IsExpired())
                {
                    kvp.Value.Touch();
                    return kvp.Value;
                }
            }
        }

        var files = Directory.GetFiles(_sessionDirectory, "*.session");
        foreach (var file in files)
        {
            var sessionId = Path.GetFileNameWithoutExtension(file);
            var session = LoadSession(sessionId);
            if (session != null && session.UserId == userId && !session.IsExpired())
            {
                session.Touch();
                lock (_lock)
                {
                    _activeSessions[session.SessionId] = session;
                }
                return session;
            }
        }

        return null;
    }

    #pragma warning disable SYSLIB0011
    private void SaveSession(UserSession session)
    {
        string filePath = GetSessionFilePath(session.SessionId);
        try
        {
            BinaryFormatter formatter = new BinaryFormatter();
            using (FileStream stream = new FileStream(filePath, FileMode.Create, FileAccess.Write))
            {
                formatter.Serialize(stream, session);
            }
        }
        catch (Exception ex)
        {
            Console.WriteLine($"[SessionManager] Error saving session {session.SessionId}: {ex.Message}");
            throw;
        }
    }

    private UserSession LoadSession(string sessionId)
    {
        string filePath = GetSessionFilePath(sessionId);
        if (!File.Exists(filePath))
        {
            return null;
        }

        try
        {
            BinaryFormatter formatter = new BinaryFormatter();
            using (FileStream stream = new FileStream(filePath, FileMode.Open, FileAccess.Read))
            {
                return (UserSession)formatter.Deserialize(stream);
            }
        }
        catch (Exception ex)
        {
            Console.WriteLine($"[SessionManager] Error loading session {sessionId}: {ex.Message}");
            return null;
        }
    }
    #pragma warning restore SYSLIB0011

    private string GetSessionFilePath(string sessionId)
    {
        return Path.Combine(_sessionDirectory, $"{sessionId}.session");
    }

    public void PrintSessionInfo(string sessionId)
    {
        var session = GetSession(sessionId);
        if (session == null)
        {
            Console.WriteLine($"Session {sessionId} not found or expired.");
            return;
        }

        Console.WriteLine("=== Session Information ===");
        Console.WriteLine(session.ToString());
        Console.WriteLine($"  Theme: {session.Preferences.Theme}");
        Console.WriteLine($"  Language: {session.Preferences.Language}");
        Console.WriteLine($"  Cart Total: {session.Cart.GetCartTotal():C}");
        Console.WriteLine("  Cart Items:");
        foreach (var item in session.Cart.Items)
        {
            Console.WriteLine($"    - {item}");
        }
        Console.WriteLine("  Permissions:");
        foreach (var perm in session.Permissions)
        {
            Console.WriteLine($"    - {perm}");
        }
        Console.WriteLine("===========================");
    }
}

public class Program
{
    public static void Main(string[] args)
    {
        string sessionDir = Path.Combine(Path.GetTempPath(), "demo_sessions");
        var manager = new SessionManager(sessionDir, TimeSpan.FromHours(2));

        Console.WriteLine("=== Session Management System Demo ===\n");

        // Create a session
        var session = manager.CreateSession("user-001", "john_doe", "john@example.com");
        Console.WriteLine($"Created session: {session.SessionId}\n");

        // Set preferences
        session.Preferences.Theme = "Dark";
        session.Preferences.Language = "en-US";
        session.Preferences.ItemsPerPage = 50;
        session.Preferences.EmailNotifications = true;
        session.Preferences.SetCustomSetting("sidebar_collapsed", "false");
        session.Preferences.SetCustomSetting("font_size", "14");

        // Add items to cart
        session.Cart.AddItem("PROD-001", "Wireless Mouse", 29.99m, 1);
        session.Cart.AddItem("PROD-002", "Mechanical Keyboard", 89.99m, 1);
        session.Cart.AddItem("PROD-003", "USB-C Hub", 45.50m, 2);
        session.Cart.AddItem("PROD-001", "Wireless Mouse", 29.99m, 1); // adds quantity

        // Add permissions
        session.AddPermission("ViewDashboard", "dashboard", PermissionLevel.Read);
        session.AddPermission("ManageProducts", "products", PermissionLevel.Write);
        session.AddPermission("AdminPanel", "admin", PermissionLevel.Admin);
        session.AddPermission("ViewReports", "reports", PermissionLevel.Read);

        // Add custom data
        session.AdditionalData["last_visited_page"] = "/products";
        session.AdditionalData["login_ip"] = "192.168.1.100";

        // Save updates
        manager.UpdateSession(session);

        // Retrieve and display session
        Console.WriteLine("\n--- Retrieving session from disk ---");
        manager.PrintSessionInfo(session.SessionId);

        // Test permission checks
        Console.WriteLine("\n--- Permission Checks ---");
        Console.WriteLine($"Can access dashboard (Read)? {session.HasPermission("dashboard", PermissionLevel.Read)}");
        Console.WriteLine($"Can write to dashboard? {session.HasPermission("dashboard", PermissionLevel.Write)}");
        Console.WriteLine($"Can write to products? {session.HasPermission("products", PermissionLevel.Write)}");
        Console.WriteLine($"Can admin products? {session.HasPermission("products", PermissionLevel.Admin)}");
        Console.WriteLine($"Can admin 'admin'? {session.HasPermission("admin", PermissionLevel.Admin)}");

        // Test cart operations
        Console.WriteLine("\n--- Cart Operations ---");
        Console.WriteLine($"Cart total: {session.Cart.GetCartTotal():C}");
        Console.WriteLine($"Item count: {session.Cart.GetItemCount()}");
        session.Cart.UpdateQuantity("PROD-003", 1);
        Console.WriteLine($"After updating USB-C Hub qty to 1: {session.Cart.GetCartTotal():C}");
        session.Cart.RemoveItem("PROD-002");
        Console.WriteLine($"After removing keyboard: {session.Cart.GetCartTotal():C}");
        manager.UpdateSession(session);

        // Create another session
        var session2 = manager.CreateSession("user-002", "jane_smith", "jane@example.com");
        session2.Cart.AddItem("PROD-005", "Monitor Stand", 120.00m, 1);
        session2.AddPermission("ViewAll", "*", PermissionLevel.Read);
        manager.UpdateSession(session2);

        // List all active sessions
        Console.WriteLine("\n--- All Active Sessions ---");
        var allSessions = manager.GetAllActiveSessions();
        foreach (var s in allSessions)
        {
            Console.WriteLine($"  {s}");
        }

        // Find session by user ID
        Console.WriteLine("\n--- Find Session by User ID ---");
        var foundSession = manager.GetSessionByUserId("user-001");
        if (foundSession != null)
        {
            Console.WriteLine($"Found session for user-001: {foundSession.SessionId}");
        }

        // Test preference custom settings
        Console.WriteLine("\n--- Custom Preference Settings ---");
        Console.WriteLine($"Sidebar collapsed: {session.Preferences.GetCustomSetting("sidebar_collapsed")}");
        Console.WriteLine($"Font size: {session.Preferences.GetCustomSetting("font_size")}");
        Console.WriteLine($"Missing setting: {session.Preferences.GetCustomSetting("nonexistent", "default_value")}");

        // Test individual permission methods
        Console.WriteLine("\n--- Individual Permission Methods ---");
        foreach (var perm in session.Permissions)
        {
            Console.WriteLine($"{perm.Name}: CanRead={perm.CanRead()}, CanWrite={perm.CanWrite()}, CanDelete={perm.CanDelete()}");
        }

        // Cleanup
        Console.WriteLine("\n--- Cleanup ---");
        manager.DestroySession(session.SessionId);
        manager.DestroySession(session2.SessionId);
        int cleaned = manager.CleanupExpiredSessions();
        Console.WriteLine($"Cleaned up {cleaned} sessions.");

        // Verify deletion
        var deletedSession = manager.GetSession(session.SessionId);
        Console.WriteLine($"Session after deletion: {(deletedSession == null ? "null (correctly deleted)" : "still exists")}");

        // Cleanup directory
        try
        {
            if (Directory.Exists(sessionDir))
                Directory.Delete(sessionDir, true);
        }
        catch { }

        Console.WriteLine("\n=== Demo Complete ===");
    }
}